You are a Swift/SwiftUI expert for the TunedVoice macOS app — a push-to-talk dictation app using on-device Parakeet TDT v3 speech recognition with CTC vocabulary boosting via FluidAudio SDK.

#### Services/Transcription/TranscriptionEngine.swift
```swift
import Foundation
import TunedVoiceKit

// TranscriptionEngineState now comes from TunedVoiceKit.
// No local definition needed.

protocol TranscriptionEngine: AnyObject, Sendable {
    var state: TranscriptionEngineState { get }
    var loadedModelID: String? { get }
    func loadModel(at modelURL: URL) async throws
    func transcribe(_ audio: CapturedAudio) async throws -> DictationResult
    func transcribePartial(_ samples: [Float]) async throws -> String
    func cancelCurrentTranscription() async
    func unloadModel() async
}

extension TranscriptionEngine {
    func transcribePartial(_ samples: [Float]) async throws -> String {
        throw TunedVoiceError.transcriptionFailed("Partial transcription not supported")
    }
}

```

#### Services/Transcription/EngineRouter.swift
```swift
import Foundation
import os
import TunedVoiceKit

/// Routes transcription calls to the Parakeet engine.
/// Dynamically enables/disables CTC keyword boosting based on settings.
///
/// Thread safety: `lastUsedOption` is the only mutable state and is protected
/// by an `OSAllocatedUnfairLock` to prevent data races when read from
/// different isolation contexts.
final class EngineRouter: TranscriptionEngine, @unchecked Sendable {
    let parakeetPath: any ParakeetEngineProtocol
    private let settingsStore: SettingsStore
    private let minerStore: VocabularyMinerStore?

    /// Which engine was used for the last transcription (for diagnostics).
    /// Protected by `_lastUsedLock` for thread-safe access.
    private let _lastUsedLock = OSAllocatedUnfairLock(initialState: TranscriptionEngineOption.parakeet)
    var lastUsedOption: TranscriptionEngineOption {
        get { _lastUsedLock.withLock { $0 } }
    }

    init(
        parakeetPath: any ParakeetEngineProtocol,
        settingsStore: SettingsStore,
        minerStore: VocabularyMinerStore? = nil
    ) {
        self.parakeetPath = parakeetPath
        self
