#### Services/Audio/AudioCaptureService.swift
```swift
import AVFoundation
import TunedVoiceKit

@MainActor
protocol AudioCaptureService: AnyObject {
    var isRecording: Bool { get }
    var targetFormat: AVAudioFormat { get }
    var lastCaptureMetadata: DictationAudioMetadata? { get }
    var levelStream: AsyncStream<AudioLevelSample> { get }
    var sampleStream: AsyncStream<[Float]> { get }
    var deviceChangeStream: AsyncStream<Void> { get }

    func startCapture() async throws
    func stopCapture() async throws -> CapturedAudio
    func cancelCapture() async
    func reset() async

    /// Prime the audio stack so subsequent startCapture() calls are faster without
    /// retaining an idle engine or microphone path.
    func warmUp()
    /// Clear any warm-up bookkeeping. Active recording teardown is handled elsewhere.
    func coolDown()

    /// Pipe the current session's TimingSession id into the capture path so the
    /// HAL tap thread can stamp `p05_first_sample` and `p12*` phases without a
    /// back-channel. Callers set this just before `startCapture()`.
    func setTimingSessionID(_ id: String?)
}

extension AudioCaptureService {
    func warmUp() {}
    func coolDown() {}
    func setTimingSessionID(_ id: String?) {}
}

```

